CREATE TABLE ops_tickets (id text NOT NULL, account_id text NOT NULL, asset_id text, type USER-DEFINED NOT NULL, priority USER-DEFINED NOT NULL DEFAULT 'MEDIUM'::"TicketPriority", status USER-DEFINED NOT NULL DEFAULT 'OPEN'::"TicketStatus", subject text NOT NULL, description text, assigned_to text, created_at timestamp without time zone NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at timestamp without time zone NOT NULL, resolved_at timestamp without time zone);


-- Table: payments
DROP TABLE IF EXISTS payments CASCADE;
CREATE TABLE payments (id integer NOT NULL DEFAULT nextval('payments_id_seq'::regclass), subscription_id integer NOT NULL, amount double precision NOT NULL, currency character varying(10) NOT NULL, status USER-DEFINED NOT NULL, payment_method_type USER-DEFINED NOT NULL, crypto_currency USER-DEFINED, wallet_address character varying(200), payment_address character varying(200), transaction_hash character varying(200), blockchain_network character varying(50), confirmations integer, required_confirmations integer, block_number integer, gas_price double precision, gas_used integer, stripe_payment_intent_id character varying(100), stripe_customer_id character varying(100), invoice_number character varying(100), invoice_url character varying(500), expires_at timestamp without time zone, retry_count integer, aml_status character varying(50), kyc_status character varying(50), risk_score double precision, compliance_score double precision, compliance_notes text, compliance_checked_at timestamp without time zone, manual_review_required boolean, payment_date timestamp without time zone, confirmed_at timestamp without time zone, created_at timestamp without time zone, updated_at timestamp without time zone);


-- Table: permissions
DROP TABLE IF EXISTS permissions CASCADE;
CREATE TABLE permissions (id text NOT NULL, resource text NOT NULL, action text NOT NULL, role_id text NOT NULL, created_at timestamp without time zone NOT NULL DEFAULT CURRENT_TIMESTAMP);


-- Table: portfolio_history
DROP TABLE IF EXISTS portfolio_history CASCADE;
CREATE TABLE portfolio_history (id integer NOT NULL DEFAULT nextval('portfolio_history_id_seq'::regclass), portfolio_id integer NOT NULL, snapshot_date timestamp without time zone NOT NULL, btc_inventory numeric NOT NULL, btc_price_usd numeric NOT NULL, inventory_value_usd numeric NOT NULL, unrealized_pl_percent numeric NOT NULL, cash_reserves numeric NOT NULL, total_portfolio_value numeric NOT NULL);


-- Table: refresh_tokens
DROP TABLE IF EXISTS refresh_tokens CASCADE;
CREATE TABLE refresh_tokens (id text NOT NULL, user_id text NOT NULL, token text NOT NULL, expires_at timestamp without time zone NOT NULL, created_at timestamp without time zone NOT NULL DEFAULT CURRENT_TIMESTAMP);

