DROP TABLE IF EXISTS roles CASCADE;
CREATE TABLE roles (id text NOT NULL, name text NOT NULL, permissions_json jsonb NOT NULL, created_at timestamp without time zone NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at timestamp without time zone NOT NULL);


