DROP TABLE IF EXISTS scheduler_leader_lock CASCADE;
CREATE TABLE scheduler_leader_lock (lock_key character varying(255) NOT NULL, process_id integer NOT NULL, hostname character varying(255) NOT NULL, acquired_at timestamp without time zone NOT NULL, expires_at timestamp without time zone NOT NULL, last_heartbeat timestamp without time zone NOT NULL, worker_info text, lock_version integer NOT NULL);

