CREATE TABLE shipments (id text NOT NULL, batch_id text NOT NULL, tracking_number text, carrier text, shipped_at timestamp without time zone, delivered_at timestamp without time zone, status USER-DEFINED NOT NULL DEFAULT 'PENDING'::"ShipmentStatus", created_at timestamp without time zone NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at timestamp without time zone NOT NULL);


