DROP TABLE IF EXISTS sla_certificate_records CASCADE;
CREATE TABLE sla_certificate_records (id integer NOT NULL DEFAULT nextval('sla_certificate_records_id_seq'::regclass), month_year integer NOT NULL, recipient_address character varying(42) NOT NULL, token_id character varying(20), contract_address character varying(42), transaction_hash character varying(66), block_number bigint, mint_status USER-DEFINED, requested_at timestamp without time zone NOT NULL, minted_at timestamp without time zone, sla_metrics_id integer, metadata_ipfs_hash character varying(100), image_ipfs_hash character varying(100), report_ipfs_hash character varying(100), is_verified boolean, verified_by character varying(42), verified_at timestamp without time zone, verification_note text, error_message text, retry_count integer);


-- Table: sla_metrics
DROP TABLE IF EXISTS sla_metrics CASCADE;
CREATE TABLE sla_metrics (id integer NOT NULL DEFAULT nextval('sla_metrics_id_seq'::regclass), recorded_at timestamp without time zone NOT NULL, month_year integer NOT NULL, uptime_percentage numeric NOT NULL, availability_percentage numeric NOT NULL, avg_response_time_ms integer NOT NULL, max_response_time_ms integer NOT NULL, min_response_time_ms integer NOT NULL, data_accuracy_percentage numeric NOT NULL, api_success_rate numeric NOT NULL, blockchain_verifications integer, ipfs_uploads integer, transparency_score numeric NOT NULL, error_count integer, critical_error_count integer, downtime_minutes integer, user_satisfaction_score numeric, feature_completion_rate numeric NOT NULL, composite_sla_score numeric NOT NULL, sla_status USER-DEFINED NOT NULL, data_source character varying(50), verified_by_blockchain boolean, ipfs_hash character varying(100));


