CREATE TABLE system_performance_logs (id integer NOT NULL DEFAULT nextval('system_performance_logs_id_seq'::regclass), "timestamp" timestamp without time zone NOT NULL, cpu_usage_percent numeric NOT NULL, memory_usage_percent numeric NOT NULL, disk_usage_percent numeric NOT NULL, network_latency_ms integer NOT NULL, bandwidth_utilization numeric NOT NULL, active_connections integer, requests_per_second numeric, error_rate numeric, db_connection_count integer, db_query_avg_time_ms integer, api_endpoints_healthy integer, api_endpoints_unhealthy integer, external_api_status text, blockchain_sync_status boolean, ipfs_service_status boolean);


