CREATE TABLE user_subscriptions (id integer NOT NULL DEFAULT nextval('user_subscriptions_id_seq'::regclass), user_id character varying NOT NULL, plan_id integer NOT NULL, status USER-DEFINED NOT NULL, started_at timestamp without time zone NOT NULL, expires_at timestamp without time zone, cancelled_at timestamp without time zone, auto_renew boolean, created_at timestamp without time zone, updated_at timestamp without time zone);


