CREATE TABLE users (id text NOT NULL, email text NOT NULL, password_hash text NOT NULL, created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP, name text, role_id text, status USER-DEFINED NOT NULL DEFAULT 'ACTIVE'::"UserStatus", updated_at timestamp without time zone, role character varying(20) DEFAULT 'user'::character varying);

